defaultSnippets.body:
repository: ${1:owner/repo}
auto_push_on_commit: true
release_branch:
  enabled: false
  naming_template: releases/{VERSION}-{SERVICE_NAME}

crates:
  enabled: true
  package_name: ${1:my-crate}
  manifest_path: ${2:Cargo.toml}
  token: ${CARGO_REGISTRY_TOKEN}
npm: null
dist:
  enabled: true
  packages: [${1:my-crate}]
  installers: [shell, powershell]
